#include <stdio.h>

long long power_mod(long long b, long long e, long long m) {
    long long result = 1;
    b %= m;
    while (e > 0) {
        if (e & 1) result = result * b % m;
        b = b * b % m;
        e >>= 1;
    }
    return result;
}

int main() {
    long long b, e, m;
    scanf("%lld %lld %lld", &b, &e, &m);
    printf("%lld\n", power_mod(b, e, m));
    return 0;
}

let power_mod b e m =
  let b = ref (b mod m) and e = ref e and r = ref 1L in
  let b = ref (Int64.of_int !b) and e = ref (Int64.of_int !e)
       and m = Int64.of_int m and r = ref 1L in
  while !e > 0L do
    if Int64.rem !e 2L = 1L then r := Int64.rem (Int64.mul !r !b) m;
    b := Int64.rem (Int64.mul !b !b) m;
    e := Int64.div !e 2L
  done;
  !r

